// ============================================================
// CATEGORY 2: BE VERBS & LINKING VERBS (121–145)
// ============================================================
const linkingVerbs = [
  w(121,'am','हूँ','first-person singular present of \'be\'','/æm/','Linking Verbs','verb','A1',['exist','be'],['aren\'t','am not'],s('I am a student of English.','I am the project manager for this account.','I am extremely passionate about learning.','I am the founder of this startup.','Every citizen is who they are.','I am so happy to be here!'),'"Am" = first person singular only. Always use \'I am\'. Never \'I is\' or \'I are\'.',null),
  w(122,'is','है (एकवचन)','third-person singular present of \'be\'','/ɪz/','Linking Verbs','verb','A1',['exists'],['isn\'t','is not'],s('He is a very good teacher.','The meeting is at 3 PM today.','This is the best opportunity of my career.','The market is growing at 15% annually.','Democracy is the voice of the people.','This is the best day ever!'),'"Is" = He/She/It/singular noun. Never \'He are\' or \'She am\'.',null),
  w(123,'are','हैं (बहुवचन)','plural or second-person present of \'be\'','/ɑːr/','Linking Verbs','verb','A1',['exist','present'],['aren\'t','are not'],s('We are a team of passionate learners.','These are the project deliverables.','You are exactly what we are looking for.','We are the market leaders in EdTech.','Citizens are the backbone of democracy.','You are amazing — never forget that!'),'"Are" = You/We/They/plural nouns. \'Is\' is singular, \'are\' is plural.',null),
  w(124,'was','था / थी (एकवचन)','past tense of \'be\' for I/he/she/it','/wɒz/','Linking Verbs','verb','A1',['existed','had been'],['wasn\'t','was not'],s('I was a student at Delhi University.','Yesterday\'s meeting was very productive.','I was nervous before the interview.','The company was founded in 2010.','The past was different — we must move forward.','That was the best biryani of my life!'),'"Was" = I/He/She/It + past. Irregular past of \'be\'.',null),
  w(125,'were','थे / थीं (बहुवचन)','past tense of \'be\' for you/we/they','/wɜːr/','Linking Verbs','verb','A1',['existed','had been'],['weren\'t','were not'],s('We were classmates in college.','There were 50 people at the conference.','They were very impressed with my performance.','Revenues were higher than expected last year.','Those were the golden days of our country.','Those were the best years of my life!'),'"Were" = You/We/They + past. Also used for unreal conditions: \'If I were you...\'',null),
  w(126,'become','बनना / हो जाना','to start to be something different','/bɪˈkʌm/','Linking Verbs','verb','A1',['turn into','grow into','transform'],['remain','stay','continue'],s('I want to become a fluent English speaker.','She has become the team leader.','I want to become a confident communicator.','Our startup has become a market leader.','We must all become better citizens.','You became exactly who I knew you would!'),'Irregular: become → became → become. \'Become + noun/adjective\': \'He became a doctor.\'',{base:'become',s3:'becomes',ing:'becoming',past:'became',pp:'become'}),
  w(127,'seem','लगना / प्रतीत होना','to appear or give the impression of being something','/siːm/','Linking Verbs','verb','A1',['appear','look','feel'],['be','remain','prove'],s('You seem tired today — get some rest.','This plan seems feasible to me.','I seem calm but I was nervous inside.','The market seems to be improving.','Things are not always what they seem.','It seems like it\'s going to rain!'),'"Seem" is a state verb. \'It seems\' = It appears. Followed by adjective or \'to be + noun\'.',null),
  w(128,'look','दिखना (adjective के साथ)','to have a particular appearance','/lʊk/','Linking Verbs','verb','A1',['appear','seem','feel'],['be','hide','conceal'],s('You look great in that formal shirt!','The project looks on track.','I look confident — even when I\'m not.','This quarter looks very promising.','Things look better in the morning.','You look like you need a vacation!'),null,null),
  w(129,'feel','महसूस होना (linking)','to seem or be perceived a certain way','/fiːl/','Linking Verbs','verb','A1',['seem','appear','sense'],['think','know','ignore'],s('I feel confident about tomorrow.','The office feels warm and welcoming.','I felt ready for every question asked.','The brand feels premium and trustworthy.','Freedom feels like breathing fresh air.','I feel like a superhero today!'),null,null),
  w(130,'sound','सुनना / लगना','to seem a certain way when heard or described','/saʊnd/','Linking Verbs','verb','A1',['seem','appear','strike'],['be','look','feel'],s('That sounds like a great idea!','Your proposal sounds very promising.','I want to sound confident and clear.','That marketing plan sounds very creative.','That sounds like good news for the country.','That sounds like a horrible plan — let\'s do it!'),null,null),
];

