const bodyHealth = [
  w(341,'head','सिर','the top part of your body with your brain, eyes, and ears','/hɛd/','Body & Health','noun','A1',['mind','brain','skull'],['foot','toe','heel'],s('Use your head — think before you speak.','The head of our department is very supportive.','Hold your head high in every interview.','He is the head of the company.','A healthy nation starts with a healthy head (leader).','Keep your head up — you\'ve got this!'),null,null),
  w(342,'hand','हाथ','the body part at the end of your arm','/hænd/','Body & Health','noun','A1',['palm','fist','fingers'],['foot','leg','toe'],s('Give me a hand — I need help.','Hands-on experience is priceless.','Shake hands firmly — it shows confidence.','Raise your hand if you have a question.','Give the poor a hand — they need it.','Give me five! You crushed it!'),null,null),
  w(343,'eye','आँख','the organ used for seeing','/aɪ/','Body & Health','noun','A1',['vision','gaze','sight'],['ear','nose','touch'],s('Keep your eye on the goal always.','I keep an eye on all deadlines.','Maintain eye contact in interviews — it builds trust.','An eye for detail separates great from average.','An eye for an eye makes the whole world blind.','I have an eye for good design — it\'s a gift!'),null,null),
  w(344,'ear','कान','the organ used for hearing','/ɪr/','Body & Health','noun','A1',['hearing','lobe','drum'],['eye','nose','mouth'],s('Lend me your ear — I have something important to say.','Listen with both ears — open your mind.','I have a good ear for language and accents.','Keep your ear to the ground — industry trends matter.','Have an ear for the voice of the people.','She has an ear for languages — incredible!'),null,null),
  w(345,'mouth','मुँह','the opening in your face for eating and speaking','/maʊθ/','Body & Health','noun','A1',['lips','jaw','teeth'],['ear','eye','nose'],s('Open your mouth and speak — don\'t be shy.','Word of mouth is the best marketing.','I kept my mouth shut and listened carefully.','Our business grew through word-of-mouth referrals.','Give voice to the mouth-less — those who cannot speak.','Open your mouth and speak your truth!'),null,null),
  w(346,'heart','दिल / हृदय','the organ that pumps blood; center of emotions','/hɑːrt/','Body & Health','noun','A1',['emotion','core','soul'],['mind','brain','logic'],s('I study English with my whole heart.','She leads the team with her heart and mind.','Follow your heart — and your prepared mind.','Customer experience is at the heart of our business.','The heart of democracy is the vote.','You\'re at the heart of everything I do!'),null,null),
  w(347,'mind','मन / दिमाग़','the part of you that thinks and feels','/maɪnd/','Body & Health','noun','A1',['brain','intellect','thought'],['body','emotion','feeling'],s('Keep your mind open to new ideas.','Mind your language in professional settings.','My mind was calm during the interview.','Great products start in great minds.','Mind your civic duties — they matter.','Mind over matter — that\'s my philosophy!'),null,null),
  w(348,'body','शरीर','the physical structure of a person','/ˈbɒd.i/','Body & Health','noun','A1',['physique','frame','form'],['mind','spirit','soul'],s('A healthy body supports a sharp mind.','Your body language speaks before your words do.','My body was tense but my mind was calm.','A strong team is the body of a strong company.','Take care of the body of our nation — its people.','Body language matters — stand tall and confident!'),null,null),
  w(349,'health','स्वास्थ्य','the state of being well in body and mind','/hɛlθ/','Body & Health','noun','A1',['wellness','fitness','wellbeing'],['illness','disease','sickness'],s('My health is my top priority.','We offer health insurance to all employees.','Good health boosts interview performance.','A healthy team is a high-performing team.','Health is a fundamental right — not a privilege.','Health is wealth — invest in yourself!'),null,null),
  w(350,'exercise','व्यायाम / कसरत','physical activity to stay healthy','/ˈɛk.sər.saɪz/','Body & Health','noun','A1',['workout','training','activity'],['rest','laziness','inactivity'],s('I exercise every morning to stay energized.','Exercise your right to speak — use English daily.','I exercise both my body and my mind daily.','We exercise good judgment in all business decisions.','Exercise your right to vote — it\'s sacred.','Exercise is the best therapy — try it!'),null,null),
  w(351,'sleep','नींद','the state of rest when your eyes are closed','/sliːp/','Body & Health','noun','A1',['rest','nap','slumber'],['wakefulness','activity','alertness'],s('Sleep is essential for language learning.','Don\'t lose sleep over small issues.','I slept well the night before the interview.','A rested team performs 40% better.','Sleep is a basic human need.','Sleep is my best friend after English practice!'),null,null),
  w(352,'medicine','दवाई / औषधि','a substance used to treat illness','/ˈmɛd.ɪ.sɪn/','Body & Health','noun','A1',['drug','treatment','remedy'],['illness','disease','poison'],s('Take your medicine on time.','I don\'t need medicine — I have discipline.','My medicine for interview nerves is preparation.','We provide medicine benefits for all employees.','Medicine should be accessible to every citizen.','Best medicine? Laughter + English practice!'),null,null),
  w(353,'sick','बीमार','physically ill; unwell','/sɪk/','Body & Health','adjective','A1',['ill','unwell','diseased'],['healthy','well','fit'],s('I felt sick but still studied for one hour.','Please inform HR if you feel sick.','I have never been sick of learning.','We care for sick employees with paid leave.','Treat the sick — it is our shared duty.','I\'m sick of excuses — time to work!'),null,null),
  w(354,'strong','मज़बूत (स्वास्थ्य में)','physically or mentally powerful','/strɒŋ/','Body & Health','adjective','A1',['fit','healthy','powerful'],['weak','frail','fragile'],s('Stay strong — English fluency is coming!','A strong body and a strong mind = a strong person.','I came into the interview strong and confident.','We build a strong company culture for strength.','Build strong communities.','You\'re stronger than yesterday — keep that energy!'),null,null),
  w(355,'pain','दर्द','an unpleasant feeling in your body','/peɪn/','Body & Health','noun','A1',['ache','discomfort','hurt'],['pleasure','comfort','relief'],s('The pain of not learning is worse than the pain of studying.','Pain is a signal — listen to your body.','Every difficult word I learned was worth the pain.','No pain, no gain — but we reduce pain where possible.','The pain of injustice should motivate us all.','No pain, no gain — and I\'m okay with that!'),null,null),
  w(356,'smile','मुस्कान / मुस्कुराना','a happy facial expression','/smaɪl/','Body & Health','noun','A1',['grin','beam','laugh'],['frown','scowl','cry'],s('Smile — it makes your English sound friendlier.','A smile is the best business card.','I smiled throughout the interview — it worked!','A smile opens more doors than any business card.','A smiling nation is a happy nation.','Smile — it confuses people who want you to fail!'),null,null),
  w(357,'walk','चलना / टहलना','the act of moving on foot','/wɔːk/','Body & Health','noun','A1',['stroll','march','hike'],['run','drive','ride'],s('A 30-minute walk clears my mind for study.','Walk the talk — do what you say you will.','I walked into the interview room with confidence.','Walk before you run — in business and in learning.','Walk toward a better future for all citizens.','My morning walk + English podcast = perfect combo!'),null,null),
  w(358,'voice','आवाज़','the sound made when you speak or sing','/vɔɪs/','Body & Health','noun','A1',['sound','tone','speech'],['silence','quiet','hush'],s('Speak in a clear, confident voice.','Your voice matters — use English to express it.','I practiced my voice tone before the interview.','The voice of the brand is our team\'s English.','Every citizen has a voice — use it.','Your voice is powerful — never stay silent!'),null,null),
  w(359,'face','चेहरा / सामना करना','the front part of the head; to confront something','/feɪs/','Body & Health','noun','A1',['features','expression','front'],['back','rear','avoid'],s('Face your fears and keep learning.','Face the client confidently — you are prepared.','I faced the interview panel with full confidence.','We face every challenge with a solution mindset.','Face the truth — it\'s the only path forward.','Face every difficulty with a smile — it disarms it!'),null,null),
  w(360,'breath','साँस','the air that goes in and out of the body','/brɛθ/','Body & Health','noun','A1',['air','inhale','respiration'],['hold','suffocate','stifle'],s('Take a deep breath before you speak.','Breath deeply — it reduces anxiety before speaking.','Before the interview, I took a deep breath.','In a healthy workplace, employees can breathe freely.','Breath of fresh air = a strong democracy.','Just breathe — you\'ve got this, no matter what!'),null,null),
];

